INSERT INTO property_list (type, city, price, no_bedrooms, no_bathrooms, size, furniture, summary, owner_id, date_listed)
VALUES
('Apartment', 'Manchester', 980, 2, 1, 70, 'Furnished', 'A modern two-bedroom apartment located close to Manchester city centre, offering excellent access to shops, restaurants, and transport links. The property features a bright open-plan living area, a fully equipped kitchen, and comfortable bedrooms, making it ideal for professionals or small families seeking convenience and comfort.', 1, '2026-03-01'),
('Terraced', 'Manchester', 1100, 3, 1, 85, 'Unfurnished', 'This well-maintained terraced house in Manchester provides generous living space with three bedrooms, a cosy lounge, and a functional kitchen. Situated in a quiet residential area with good access to local amenities and transport, it is well suited for families looking for a comfortable and practical home.', 2, '2026-03-02'),
('Detached', 'Manchester', 1800, 4, 3, 150, 'Semi-Furnished', 'A spacious detached property in Manchester offering four bedrooms, multiple bathrooms, and large living areas. The home includes a private garden and driveway, making it ideal for families. Located in a desirable neighbourhood close to schools and amenities, it offers both comfort and convenience.', 3, '2026-03-03'),
('Bungalow', 'Manchester', 1200, 2, 1, 80, 'Furnished', 'This charming bungalow in Manchester offers comfortable single-level living with two bedrooms, a bright lounge, and a well-equipped kitchen. The property benefits from a private garden and off-street parking, making it ideal for those seeking a quieter lifestyle while staying close to the city.', 1, '2026-03-04'),
('Semi-Detached', 'Manchester', 1400, 3, 2, 105, 'Unfurnished', 'A well-presented semi-detached home in Manchester featuring three bedrooms, two bathrooms, and spacious living areas. The property includes a private garden and driveway, providing a great environment for families. Conveniently located near schools, shops, and transport links for easy commuting.', 2, '2026-03-05'),
('Apartment', 'London', 2000, 2, 1, 65, 'Furnished', 'A modern apartment in central London offering two bedrooms, a bright living space, and a fully fitted kitchen. Located close to major transport links, shops, and restaurants, this property is perfect for professionals seeking a vibrant and convenient city lifestyle.', 2, '2026-03-11'),
('Terraced', 'London', 2300, 3, 2, 90, 'Semi-Furnished', 'This attractive terraced house in London features three bedrooms, two bathrooms, and spacious living areas. Combining traditional character with modern features, the property is located near excellent transport links, making it ideal for families or professionals working in the city.', 3, '2026-03-12'),
('Detached', 'London', 3500, 5, 3, 180, 'Unfurnished', 'A large detached home in London offering five bedrooms, multiple bathrooms, and extensive living space. The property includes a private garden and driveway, providing a rare opportunity for spacious family living in the capital while remaining close to key amenities.', 1, '2026-03-13'),
('Bungalow', 'London', 2100, 2, 1, 85, 'Furnished', 'A rare bungalow in London offering comfortable single-level living with two bedrooms, a bright lounge, and a modern kitchen. The property includes a private garden, providing a peaceful retreat within the city and easy access to local amenities and transport links.', 2, '2026-03-14'),
('Semi-Detached', 'London', 2700, 4, 2, 120, 'Semi-Furnished', 'A spacious semi-detached home in London featuring four bedrooms, modern interiors, and generous living space. Located in a desirable neighbourhood close to schools, transport, and amenities, it is ideal for families.', 3, '2026-03-15'),
('Apartment', 'Birmingham', 900, 2, 1, 65, 'Furnished', 'A modern apartment in Birmingham offering two bedrooms, a bright living area, and a fully fitted kitchen. Located close to the city centre, the property provides easy access to shops and transport.', 3, '2026-03-21'),
('Terraced', 'Birmingham', 950, 3, 1, 80, 'Unfurnished', 'This terraced home in Birmingham offers three bedrooms, a spacious lounge, and a practical kitchen. Situated in a well-connected area close to local amenities.', 1, '2026-03-22'),
('Detached', 'Birmingham', 1700, 4, 2, 140, 'Semi-Furnished', 'A spacious detached house in Birmingham featuring four bedrooms, a modern kitchen, and large living areas. The property includes a private garden and driveway.', 2, '2026-03-23'),
('Bungalow', 'Birmingham', 1100, 2, 1, 78, 'Furnished', 'A cosy bungalow in Birmingham offering two bedrooms and comfortable living space. The property includes a private garden and is located in a quiet residential area.', 3, '2026-03-24'),
('Semi-Detached', 'Birmingham', 1300, 3, 2, 105, 'Unfurnished', 'A semi-detached home in Birmingham offering three bedrooms, two bathrooms, and spacious living areas. The property includes a garden and driveway.', 1, '2026-03-25'),
('Apartment', 'Bristol', 1400, 2, 1, 70, 'Furnished', 'A stylish apartment in Bristol city centre offering two bedrooms, a modern kitchen, and a bright living area. Close to shops and transport links.', 2, '2026-03-26'),
('Terraced', 'Bristol', 1500, 3, 2, 90, 'Semi-Furnished', 'This terraced house in Bristol offers three bedrooms, two bathrooms, and a spacious living area. Located in a popular area near amenities.', 3, '2026-03-27'),
('Detached', 'Bristol', 2200, 4, 3, 145, 'Unfurnished', 'A large detached home in Bristol offering four bedrooms, multiple bathrooms, and generous living space. Ideal for families.', 1, '2026-02-15'),
('Bungalow', 'Bristol', 1600, 2, 1, 80, 'Furnished', 'A well-maintained bungalow in Bristol offering two bedrooms and a bright living area. Located in a quiet residential area.', 2, '2026-02-10'),
('Semi-Detached', 'Bristol', 1750, 3, 2, 110, 'Semi-Furnished', 'A spacious semi-detached home in Bristol featuring three bedrooms and modern living areas. Close to schools and amenities.', 3, '2026-02-05'),
('Apartment', 'York', 1200, 2, 1, 65, 'Furnished', 'A modern apartment in York located near the historic city centre. The property offers two bedrooms and a bright living area.', 1, '2026-01-20'),
('Terraced', 'York', 1300, 3, 1, 85, 'Unfurnished', 'A charming terraced house in York offering three bedrooms and a practical layout. Located in a quiet area.', 2, '2026-01-15'),
('Detached', 'York', 2000, 4, 2, 140, 'Semi-Furnished', 'A spacious detached home in York featuring four bedrooms, large living areas, and a private garden.', 3, '2026-01-10'),
('Bungalow', 'York', 1350, 2, 1, 75, 'Furnished', 'A cosy bungalow in York offering two bedrooms and a bright living space. Ideal for relaxed living.', 1, '2026-01-05'),
('Semi-Detached', 'York', 1500, 3, 2, 100, 'Unfurnished', 'A semi-detached home in York offering three bedrooms and spacious living areas. Conveniently located near amenities.', 2, '2026-01-01');
